package main

import (
    "errors"
    "log"
)

// Compliant: Consolidated logic for identical behaviors
func calculateDiscount(userType string, amount float64) float64 {
    // GOOD: Group similar user types together
    switch userType {
    case "premium", "gold", "silver":
        return calculateStandardDiscount(amount)
    default:
        return 0
    }
}

func calculateStandardDiscount(amount float64) float64 {
    // GOOD: Common logic extracted to separate function
    if amount > 100 {
        return amount * 0.1
    }
    return 0
}

// Alternative approach with map-based logic
var discountRules = map[string]func(float64) float64{
    "premium": calculateStandardDiscount,
    "gold":    calculateStandardDiscount,
    "silver":  calculateStandardDiscount,
}

func calculateDiscountMap(userType string, amount float64) float64 {
    // GOOD: Use map to avoid duplicate implementations
    if discountFunc, exists := discountRules[userType]; exists {
        return discountFunc(amount)
    }
    return 0
}

func processPayment(method string, amount float64) error {
    // GOOD: Check for supported methods first
    supportedMethods := []string{"credit", "debit"}

    if !contains(supportedMethods, method) {
        return errors.New("unsupported payment method")
    }

    // GOOD: Common processing logic
    return processCardPayment(amount)
}

func processCardPayment(amount float64) error {
    // GOOD: Consolidated card processing logic
    log.Printf("Processing payment: %.2f", amount)
    return chargeCard(amount)
}

func contains(slice []string, item string) bool {
    for _, s := range slice {
        if s == item {
            return true
        }
    }
    return false
}
